'use client';

import { useState, useRef } from "react";
import { Button } from "@/components/ui/button";
import { Dropzone, DropzoneContent, DropzoneEmptyState } from "@/components/ui/shadcn-io/dropzone";

export default function Page() {
  const [contextFiles, setContextFiles] = useState<File[] | undefined>();
  const [templateFile, setTemplateFile] = useState<File | undefined>();

  const [reasoningBlocks, setReasoningBlocks] = useState<string[]>([]);
  const [currentReasoning, setCurrentReasoning] = useState("");
  const [finalOutput, setFinalOutput] = useState("");
  const [outputFile, setOutputFile] = useState<string | null>(null);

  const [isStreaming, setIsStreaming] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);

  const appendReasoning = (txt: string) => {
    setCurrentReasoning(prev => prev + txt);
  };

  const startNewReasoningBlock = () => {
    setReasoningBlocks(prev => [...prev, currentReasoning]);
    setCurrentReasoning("");
  };

  const appendOutput = (txt: string) => {
    setFinalOutput(prev => prev + txt);
  };

  const uploadAndStream = async () => {
    setIsStreaming(true);
    setCurrentReasoning("");
    setReasoningBlocks([]);
    setFinalOutput("");
    setOutputFile(null);

    const form = new FormData();
    contextFiles?.forEach(f => form.append("contextFiles", f));
    if (templateFile) form.append("templateFiles", templateFile);

    const resp = await fetch("/api/upload", { method: "POST", body: form });

    if (!resp.body) return;

    const reader = resp.body.getReader();
    const decoder = new TextDecoder();

    while (true) {
      const { value, done } = await reader.read();
      if (done) break;
      const chunk = decoder.decode(value);

      const events = chunk.split("\n\n").filter(Boolean);

      for (const evt of events) {
        if (!evt.startsWith("data: ")) continue;
        const json = JSON.parse(evt.replace("data: ", ""));

        switch (json.event) {
          case "reasoning.delta":
            appendReasoning(json.delta);
            break;

          case "reasoning.done":
            startNewReasoningBlock();
            break;

          case "output.delta":
            // hide reasoning blocks when output starts
            appendOutput(json.delta);
            break;

          case "output.done":
            setFinalOutput(json.text);
            break;

          case "completed":
            setOutputFile(json.output_file);
            break;

          case "error":
            appendOutput(`ERROR: ${json.message}`);
            break;
        }

        scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight);
      }
    }

    setIsStreaming(false);
  };

  return (
    <div className="p-10 max-w-4xl mx-auto space-y-8">

      {/* Upload UI unchanged */}
      {/* ... */}

      <Button onClick={uploadAndStream} disabled={isStreaming}>
        {isStreaming ? "Processing…" : "Submit"}
      </Button>

      {/* Reasoning section */}
      {reasoningBlocks.length > 0 || currentReasoning !== "" ? (
        <div className="border rounded p-4 bg-gray-50 max-h-64 overflow-y-auto" ref={scrollRef}>
          <h2 className="font-bold mb-3">Reasoning</h2>

          {reasoningBlocks.map((block, i) => (
            <details key={i} className="mb-2" open={false}>
              <summary className="cursor-pointer font-semibold">Stage {i + 1}</summary>
              <pre className="whitespace-pre-wrap">{block}</pre>
            </details>
          ))}

          {/* Live block */}
          {currentReasoning && (
            <details open>
              <summary className="cursor-pointer font-semibold">Current Stage</summary>
              <pre className="whitespace-pre-wrap">{currentReasoning}</pre>
            </details>
          )}
        </div>
      ) : null}

      {/* Final output */}
      {finalOutput && (
        <div className="border rounded p-4 bg-white shadow">
          <h2 className="font-bold mb-2">Final Output</h2>
          <pre className="whitespace-pre-wrap">{finalOutput}</pre>
        </div>
      )}

      {/* Download link */}
      {outputFile && (
        <a
          href={`/download?path=${encodeURIComponent(outputFile)}`}
          className="text-blue-600 underline"
        >
          Download output file
        </a>
      )}
    </div>
  );
}